// Generate all skills
let created = 0;
let skipped = 0;
const summary = {};

for (const app of apps) {
  const skillDir = path.join(SKILLS_DIR, app.domain, app.name);
  const skillFile = path.join(skillDir, 'SKILL.md');

  if (!summary[app.domain]) {
    summary[app.domain] = [];
  }
  summary[app.domain].push(app.name);

  if (fs.existsSync(skillFile)) {
    skipped++;
    continue;
  }

  fs.mkdirSync(skillDir, { recursive: true });
  fs.writeFileSync(skillFile, generateSkillContent(app));
  created++;
}

console.log(`\n✅ Skills Generation Complete!`);
console.log(`   Created: ${created}`);
console.log(`   Skipped (existing): ${skipped}`);
console.log(`   Total apps: ${apps.length}`);
console.log(`\n📂 Skills by Domain:`);
for (const [domain, skills] of Object.entries(summary).sort()) {
  console.log(`\n   ${domain}/ (${skills.length} skills)`);
  for (const skill of skills) {
    console.log(`     - ${skill}`);
  }
}
